import pandas as pd

def read_text(infile):
    """Read a text coordinate file and return its string representation."""
    rows = []
    with open(infile, 'r') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split()
            chrom_rest = parts[0]
            if ':' in chrom_rest:
                chrom, rest = chrom_rest.split(':', 1)
            else:
                chrom = chrom_rest
                rest = ''
            if '-' in rest:
                start_str, end_str = rest.split('-', 1)
            else:
                start_str, end_str = rest, ''
            try:
                start = int(start_str)
            except ValueError:
                start = start_str
            try:
                end = int(end_str)
            except ValueError:
                end = end_str
            gene = parts[1] if len(parts) > 1 else '-'
            rows.append((chrom, start, end, gene))
    if rows:
        df = pd.DataFrame(rows, columns=['chromosome', 'start', 'end', 'gene'])
    else:
        df = pd.DataFrame(columns=['chromosome', 'start', 'end', 'gene'])
    return str(df)
